const item = $input.first().json;
const indirizzo = String(item.owner_data?.indirizzo || '').trim();
const parti = indirizzo.split(',');
const localita = (parti[1] || parti[0] || '').trim();

return [{
    json: {
        ...item,
        cleaned_address: indirizzo,
        search_query: localita,
        nominatim_url: 'https://nominatim.openstreetmap.org/search?q=' + encodeURIComponent(localita) + '&format=jsonv2&limit=1&addressdetails=1'
    }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: BOM_Resource_Extractor
// DESC: Estrae e unifica i materiali teorici con le risorse pratiche del BOM
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero dei materiali originari generati dall'Orchestratore (Teoria)
const originalMaterials = item.orchestrator_output?.orchestration_blueprint?.required_materials || [];

// 2. Creiamo un Set per garantire la rimozione automatica di eventuali duplicati
const uniqueResources = new Set();

// Aggiungiamo i materiali originari puliti da spazi bianchi
originalMaterials.forEach(m => {
    const trimmed = String(m).trim();
    if (trimmed) uniqueResources.add(trimmed);
});

// 3. Scansione ciclica di tutte le fasi (stages) e di tutti gli step del BOM (Pratica)
const bomList = item.bom_output?.bom || [];

for (const subprocess of bomList) {
    if (subprocess.stages && Array.isArray(subprocess.stages)) {
        for (const stage of subprocess.stages) {
            if (stage.steps && Array.isArray(stage.steps)) {
                for (const step of stage.steps) {
                    if (step.required_resources && Array.isArray(step.required_resources)) {
                        for (const resource of step.required_resources) {
                            const trimmedResource = String(resource).trim();
                            if (trimmedResource) {
                                uniqueResources.add(trimmedResource);
                            }
                        }
                    }
                }
            }
        }
    }
}

// 4. Conversione del Set in un array pulito definitivo
const finalEnrichedMaterials = Array.from(uniqueResources);

// 5. Restituzione del contesto originario con l'aggiunta della lista arricchita
return [{
    json: {        enriched_required_materials: finalEnrichedMaterials
    }
}];

